        assert.strictEqual(c3.isInfinite(), false);
        assert.strictEqual(c4.isInfinite(), false);
        done();
    });

    it('test infinite complex numbers return true', function(done) {
        // Test complex numbers with infinite components
        let c1 = new complex_js(Infinity, 0);
        let c2 = new complex_js(0, Infinity);
        let c3 = new complex_js(Infinity, Infinity);
        let c4 = new complex_js(-Infinity, 5);
